import React, { useState } from 'react';

export default function FigmaChat() {
    const [messages, setMessages] = useState([
        { id: 1, name: 'Женя', text: 'Всем привет', likes: 567, liked: false },
        { id: 2, name: 'Женя', text: 'Какое-то сообщение длиннее, чем 1 строка.', likes: 11, liked: false },
        { id: 3, name: 'Женя', text: 'Всем привет', likes: 0, liked: false },
        { id: 4, name: 'Женя', text: 'Всем привет', likes: 15, liked: true },
        { id: 5, name: 'Женя', text: 'Всем привет', likes: 42, liked: false },
        { id: 6, name: 'Женя', text: 'Всем привет', likes: 0, liked: false },
    ]);
    const [activeTab, setActiveTab] = useState('chat');
    const [newMessage, setNewMessage] = useState('');
    const [chatName, setChatName] = useState('Нина');
    const [editingName, setEditingName] = useState(false);

    const handleLike = (id) => {
        setMessages(prev => prev.map(msg =>
            msg.id === id ? { ...msg, liked: !msg.liked, likes: msg.liked ? msg.likes - 1 : msg.likes + 1 } : msg
        ));
    };

    const sendMessage = () => {
        if (!newMessage.trim()) return;
        setMessages(prev => [...prev, { id: Date.now(), name: chatName, text: newMessage, likes: 0, liked: false }]);
        setNewMessage('');
    };

    return (
        <div className="chat-95">
            <div className="chat-96">
                <div className="chat-97">
                    <div className="forum_tabs-98">
                        <div className={`property-1-${activeTab === 'chat' ? 'active' : 'unactive'}`} onClick={() => setActiveTab('chat')}>
                            <p className="text-100">Чат</p>
                            {activeTab === 'chat' && <div className="underline-101"></div>}
                        </div>
                        <div className={`property-1-${activeTab === 'qa' ? 'active' : 'unactive'}`} onClick={() => setActiveTab('qa')}>
                            <p className="text-103">Вопрос / ответ</p>
                            {activeTab === 'qa' && <div className="underline-101"></div>}
                        </div>
                    </div>
                    <div className="messages-104">
                        <div className="messages-105">
                            {messages.map(msg => (
                                <div key={msg.id} className="property-1-default">
                                    <div className="name_message-107">
                                        <p className="text-108">{msg.name}</p>
                                        <p className="text-109">{msg.text}</p>
                                    </div>
                                    <div className="property-1-like" onClick={() => handleLike(msg.id)}>
                                        <svg width="18" height="18" viewBox="0 0 24 24" fill={msg.liked ? "#8B5CF6" : "none"} stroke={msg.liked ? "#8B5CF6" : "#999"} strokeWidth="2">
                                            <path d="M20 8.5C20 12 16 15 12 18C8 15 4 12 4 8.5C4 6 6 4 8.5 4C10 4 11.5 5 12 6C12.5 5 14 4 15.5 4C18 4 20 6 20 8.5Z" />
                                        </svg>
                                        <p className="text-113">{msg.likes}</p>
                                    </div>
                                </div>
                            ))}
                        </div>
                        <div className="scroll-bar"><div className="bg-155"></div><div className="scroll-156"></div></div>
                    </div>
                </div>
                <div className="input_form-157">
                    <div className="input_form-158">
                        <div className="property-1-default" style={{ flex: 1 }}>
                            <input type="text" value={newMessage} onChange={e => setNewMessage(e.target.value)} placeholder="Tекст" className="message-input" onKeyPress={e => e.key === 'Enter' && sendMessage()} />
                            <div className="property-1-smile">😊</div>
                        </div>
                        <div className="property-1-default" onClick={sendMessage}><p className="text-167">Отправить</p></div>
                    </div>
                    <div className="name_edit-168">
                        <div className="chatname-169">
                            <p className="text-170">Имя в чате:</p>
                            {editingName ? (
                                <input value={chatName} onChange={e => setChatName(e.target.value)} onBlur={() => setEditingName(false)} autoFocus style={{ background: '#3A3A3A', border: 'none', color: 'white', padding: '2px 8px', borderRadius: '4px' }} />
                            ) : (
                                <p className="text-171" onClick={() => setEditingName(true)}>{chatName}</p>
                            )}
                        </div>
                        <div className="property-1-default" onClick={() => setEditingName(true)}><p className="text-173">Ред.</p></div>
                    </div>
                </div>
            </div>
        </div>
    );
}
